/**
 * @summary Reseller dashboard referrals
 */
export const getGetResellerReferralsUrl = (
  params?: GetResellerReferralsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/dashboard/reseller/referrals?${stringifiedParams}`
    : `/api/dashboard/reseller/referrals`;
};

export const getResellerReferrals = async (
  params?: GetResellerReferralsParams,
  options?: RequestInit,
): Promise<ReferralListResponse> => {
  return customFetch<ReferralListResponse>(getGetResellerReferralsUrl(params), {
    ...options,
    method: "GET",
  });
};

